// locales/index.ts
var coreMessages = {
  en: stripMeta(en_default),
  ar: stripMeta(ar_default),
  sl: stripMeta(sl_default)
};
var localeMeta = {
  en: { locale: "en", direction: "ltr" },
  ar: { locale: "ar", direction: "rtl" },
  sl: { locale: "sl", direction: "ltr" }
};
function mergeMessages(locale, projectMessages) {
  return { ...coreMessages[locale], ...stripMeta(projectMessages) };
}
function stripMeta(obj) {
  const result = {};
  for (const [key, value] of Object.entries(obj)) {
    if (key.startsWith("$")) continue;
    if (typeof value === "string") {
      result[key] = value;
    }
  }
  return result;
}

export { coreMessages, localeMeta, mergeMessages };
